function LFightManager:ClearAllBattle()
    printInfoN("ClearAllBattle")

    local battles = self._runningBattles
    self._runningBattles = {}
    if battles then
        for k, v in pairs(battles) do
            for k1, v1 in ipairs(v) do
                v1:Destroy()
            end
        end
    end

    self:DestroyOldBattle()

    local battleList = self._waitRemoveBattle
    self._waitRemoveBattle = {}
    for k, v in pairs(battleList) do
        v:Destroy()
    end
end

--删除场景遗留的战斗显示对象
function LFightManager:ClearWaitRemoveBattleQueue()
    local battleList = self._waitRemoveBattle
    self._waitRemoveBattle = {}
    for k, v in pairs(battleList) do
        v:Destroy()
    end
end

