function LFightManager:OnPlayBattleVideo(reportId, combatExtraDatas, combatType)
    combatType = combatType or LCombatTypeConst.COMBAT_BATTLE_VIDEO
    if not self._videoCombats[combatType] then
        return
    end
    combatExtraDatas.isNew = true
    gModelBattle:RecordVideoBattleLife(combatType, true)
    gModelBattle:StartFromReportId(reportId, combatType, combatExtraDatas)

end

function LFightManager:OnPlayMultiVideo(multiReport, combatExtraDatas, combatType)
    combatType = combatType or LCombatTypeConst.COMBAT_BATTLE_VIDEO
    if not self._videoCombats[combatType] then
        return
    end
    combatExtraDatas.isNew = true
    gModelBattle:RecordVideoBattleLife(combatType, true)
    gModelBattle:StartFromMultiReport(multiReport, combatType, combatExtraDatas)
end

