---进入布阵 或者 将播放后台战斗
function LFightManager:PrepareGoToBattle(combatType, extraData)

    if gModelBattle:IsEndlessCombat(combatType) then
        ---无尽试炼战斗之间有间隙，需要特殊处理
        local isFighting = gModelEndles:IsEndlessFighting()
        if not isFighting then
            self:PrepareGoToBattleInter(combatType, extraData)
        else
            local curType = gModelEndles:GetCurFightCombatType()
            if curType ~= combatType then
                return
            end
            if gModelEndles:HaveNewSelectBuff() then
                local combatData = gModelEndles:FormatEndlessCombatData()
                GF.OpenWnd("UIUendBfPop", { combatData = combatData })
            else
                if self:CanBattleToFront(combatType) then
                    self:PrepareGoToBattleInter(combatType, extraData)
                end
            end
        end
    else
        self:PrepareGoToBattleInter(combatType, extraData)
    end

end

function LFightManager:PrepareGoToBattleInter(combatType, extraData)
    local para = nil
    --GF.CloseWndByName("UIMinFight")
    GF.CloseWndByName("UIFightPrepare")
    GF.CloseWndByName("UIFightSowWin")
    local changeSuc = self:TryChangeToActive(combatType)
    if not changeSuc then
        para = extraData or {}
        para.combatType = combatType

        if not para.battleMapName then
            local mapRes = gModelBattle:GetBattleMapRes(para)
            para.battleMapName = mapRes
        end

        if not para.musicName then
            local musicRes = gModelBattle:GetBattleBgMusic(combatType)
            para.musicName = musicRes
        end
        para.isNew = true
        para.meName = para.meName or gModelPlayer:GetPlayerName(),
        GF.ChangeMap("LBattleMap", false, { combatType = combatType, extraData = para })
    end
end

