function LFightManager:StartSimulationBattle(reportId, combatExtraData)
    local combatType = LCombatTypeConst.COMBAT_BATTLE_VIDEO_SIMULATION
    self:LoadSimulationBattleReport(reportId, function(reportTable, isPb)
        if not reportTable then
            return
        end

        printInfoN("report id" .. reportId)
        if (CS.IsUnityEdit()) and string.find(reportId, "pb") then
            local tbl = LProtoHelper.ProtoToPureTable(reportTable)
            local str = JSON.encode(tbl)
            gLFightManager:SaveReportToFile(reportId .. "tojson", str)
        end
        combatExtraData.combatType = combatType

        self:StartBattle(reportId, combatType, combatExtraData, reportTable)
    end)
end

function LFightManager:LoadSimulationBattleReport(reportId, onLoadReport)
    local filePath = reportId .. ".bytes"

    --CS.ClearUnityAsset(textAsset)

    local isPb = false
    local reportTable = nil

    if string.find(filePath, "pb") then
        isPb = true
        ---@type LxTextAsset
        local textAsset = require("LApp.component.res.LxTextAsset"):New("AnyThing/Report/" .. filePath)
        self._textAsset = textAsset
        textAsset:SetLoadedCallback(function(assets,filePath)
            local bytes = assets.bytes
            local msgId = LProtoHelper.GetProtoId("CombatReportResp")
            local protoReader = PJXProtoMessage.New()
            protoReader:SetMessage(bytes)
            local reportTable = LProtoHelper.ConvertToProto(msgId,protoReader:GetMessage())

            if self._textAsset then
                self._textAsset:Dispose()
                self._textAsset = nil
            end

            if not reportTable then
                LogError("report is not json format fileid="..tostring(reportId))
                if onLoadReport then onLoadReport(nil, isPb) end
                return
            end

            if onLoadReport then onLoadReport(reportTable, isPb) end
        end)
        textAsset:Load()
    else
        local textAsset = require("LApp.component.res.LxTextAsset"):New("AnyThing/Report/" .. filePath)
        self._textAsset = textAsset
        textAsset:SetLoadedCallback(function(respTextAsset, respFilePath)
            local fileStr = respTextAsset.text
            reportTable = JSON.decode(fileStr)
            fileStr = nil
            respTextAsset = nil

            if self._textAsset then
                self._textAsset:Dispose()
                self._textAsset = nil
            end

            if not reportTable then
                LogError("report is not json format fileid="..tostring(reportId))
                if onLoadReport then onLoadReport(nil, isPb) end
                return
            end

            if onLoadReport then onLoadReport(reportTable, isPb) end
        end)
        textAsset:Load()
    end

end

