function LFightManager:StartLocalPbReportBattle(reportId, combatExtraData)
    local filePath = CS.AppPersistentDataPath() .. "fightlog/" .. reportId .. ".log"
    local bytes = CS.FileReadBytes(filePath)
    local msgId = LProtoHelper.GetProtoId("CombatReportResp")
    local protoReader = PJXProtoMessage.New()
    protoReader:SetMessage(bytes)
    local reportTable = LProtoHelper.ConvertToProto(msgId,protoReader:GetMessage())
    local combatType = LCombatTypeConst.COMBAT_TEST_LOCAL_FILE
    combatExtraData.rewardTable = reportTable
    combatExtraData.isNew = true
    combatExtraData.combatType = reportTable.combatType
    self:StartBattle(reportId, combatType, combatExtraData, reportTable)

    if (CS.IsUnityEdit()) then
        local tbl = LProtoHelper.ProtoToPureTable(reportTable)
        local str = JSON.encode(tbl)
        self:SaveReportToFile(reportId .. "tojson", str)
    end
end

function LFightManager:GetLocalCacheReport(reportId, combatExtraData)
    --local reportId = "inst-player-1657201588694700"
    local filePath = CS.AppPersistentDataPath() .. "fightlog/" .. reportId .. ".log"
    local fileStr = CS.FileReadText(filePath)
    local reportTable = JSON.decode(fileStr)
    if not reportTable then
        LogError("report is not json format fileid =" .. tostring(reportId))
        return
    end

    print("start test fight " .. reportId)
    return reportTable
end

function LFightManager:StartBattle(reportId, combatType, combatExtraData, reportTable)
    if reportTable == nil then
        return
    end

    local isFront = self:CheckStartBattleState(combatType)
    if isFront then
        combatExtraData.isBattleToBackground = false
    end

    if not combatExtraData.isBattleToBackground then
        self:TryChangeToBackground(combatType)
    end

    local battleUnit = LFightUnit:New()

    local fullExtraData = self:FormatBattleExtraData(combatExtraData)
    battleUnit:Init(reportId, combatType)
    battleUnit:InitCombatExtraData(combatExtraData)
    battleUnit:InitBattleReport(reportTable)
    self:AddCombatByType(combatType, battleUnit)

    if combatExtraData.isBattleToBackground then
        -- 开始后台战斗
        battleUnit:StartBackgroundBattle()
    else

        self:SetCurCombatType(combatType)

        local args = { combatType = combatType, extraData = fullExtraData, noNeedBackground = false, isInFight = true }
        local isSceneReady = self:IsBattleSceneReady(combatType, fullExtraData.battleMapName)
        printInfoN(string.format("start battle isSceneReady %s", tostring(isSceneReady)))
        local curMap = GF.GetCurMap()
        if isSceneReady then
            curMap:ResetMap(args)
            self:DoActiveBattleStart()
        else
            if curMap and curMap:IsSameMap("LBattleMap") then
                local mapArg = curMap:GetMapArgList() or {}
                mapArg.noNeedBackground = true
                curMap:ModifyMapArg(mapArg)
            end
            GF.ChangeMap("LBattleMap", false, args)
        end
    end
    FireEvent(EventNames.START_BATTLE_State)

end

function LFightManager:DoActiveBattleStart()
    local curBattleUnit = self:GetCurBattleUnit()
    if not curBattleUnit or curBattleUnit:IsBattleInit() then
        return
    end

    curBattleUnit:AttachMapTrans(self._mapTrans)
    curBattleUnit:StartFrontBattle()
    FireEvent(EventNames.START_BATTLE)
    self:PlayMapMusic(curBattleUnit:GetCombatExtraData())

    local exceptsWnd = {
        ["UIFight"] = true,
        ["UIBulletSay"] = true,
        ["UILvUp"] = true,
        ["UITaCutToEff"] = true,
        ["UIOrdinResult"] = true,
        ["UIringFightResult"] = true,
        ["WndCrossServerBattleResult"] = true,
        ["UIKuafuGradMatching"] = true,
        ["UISayPop"] = true,
    }
    gLGameUI:CloseAllButExcept(exceptsWnd)

    gModelGameHelper:RefreshGameSpeed()

end

function LFightManager:IsBattleSceneReady(combatType, mapResName)
    local curMap = GF.GetCurMap()
    if not curMap then
        return false
    end
    if not curMap:IsSameMap("LBattleMap") then
        return false
    end
    if not curMap:IsReadyForCombat(combatType) then
        return false
    end

    if string.isempty(mapResName) then
        mapResName = "MapBattle1001"
    end

    local curMapName = curMap:GetMapName()
    if curMapName ~= mapResName then
        return false
    end

    return true
end

function LFightManager:SetCurCombatType(combatType)

    if self._curCombatType then
        self:ClearCombatByIfAllEnd(self._curCombatType)
    end

    self._curCombatType = combatType


end

-----无表现战斗，提取战报查看战斗数据详情
function LFightManager:FormatBattleDetailData(reportTable)
    local battleDetailData = {}
    local formationDataA = reportTable.formationA
    local formationDataB = reportTable.formationB

    local formationA = {}
    local teamAGrids = formationDataA.grids
    battleDetailData.formationAOtherData = {
        playerId = formationDataA.playerId,
        serverId = formationDataA.serverId,
        mvpHeroRefId = tonumber(formationDataA.mvpHeroRefId),
        formationName = reportTable:GetFormationName(true),
        tacticsId = formationDataA.tacticsId
    }
    for k, v in pairs(teamAGrids) do
        local heroA = {
            id = v.id,
            refId = v.refId,
            star = v.star,
            level = v.level,
            isMon = v.monster == 1,
            fightPower = v.fightPower,
            resonance = v.resonance,
            skinId = v.skinId,
            grade = v.grade,
            quality = v.quality,
            form = v.form,
        }
        table.insert(formationA, heroA)
    end

    local formationB = {}
    local teamBGrids = formationDataB.grids
    battleDetailData.formationBOtherData = {
        playerId = formationDataB.playerId,
        serverId = formationDataB.serverId,
        mvpHeroRefId = tonumber(formationDataB.mvpHeroRefId),
        formationName = reportTable:GetFormationName(false),
        tacticsId = formationDataB.tacticsId
    }
    for k, v in pairs(teamBGrids) do
        local heroB = {
            id = v.id,
            refId = v.refId,
            star = v.star,
            level = v.level,
            isMon = v.monster == 1,
            fightPower = v.fightPower,
            resonance = v.resonance,
            skinId = v.skinId,
            grade = v.grade,
            quality = v.quality,
            form = v.form,
        }
        table.insert(formationB, heroB)
    end

    battleDetailData.formationA = formationA
    battleDetailData.formationB = formationB
    battleDetailData.reportTableID = reportTable.id
    battleDetailData.combatType = reportTable.combatType
    battleDetailData.settlementReport = gModelBattle:GetBattleDetailsDataByReport(reportTable)
    battleDetailData.hurtCountA = reportTable.details.hurtCountA
    battleDetailData.hurtCountB = reportTable.details.hurtCountB
    return battleDetailData
end

