---@return LFightUnit  当前前台播放的战斗
function LFightManager:GetCurBattleUnit()
    if not self._curCombatType then
        return
    end

    local list = self._runningBattles and self._runningBattles[self._curCombatType]
    if not list then
        return
    end

    local cnt = #list
    if cnt == 0 then
        return
    else
        for k, v in ipairs(list) do
            if not v:IsBackgroundPlay() then
                return v
            end
        end
    end
end

---切换战斗到后台
function LFightManager:TryChangeToBackground(newCombatType)
    local curBattleUnit = self:GetCurBattleUnit()

    if not curBattleUnit then
        return
    end

    local combatType = curBattleUnit:GetCombatType()
    if combatType ~= newCombatType then
        local isNoNeed = self:IsNoNeedBackground(combatType)
        if isNoNeed then
            local battles = self._runningBattles[combatType]
            if battles then
                for k, v in ipairs(battles) do
                    v:ExitBattleImpl()
                end
            end

            if self:IsVideoCombat(combatType) then
                gModelBattle:RecordVideoBattleLife(combatType, false)
            end
            return
        end
    end

    local isEnd = curBattleUnit:IsEndExecute()
    if not isEnd then
        curBattleUnit:ChangeToBackground()
    end

    gModelGameHelper:RefreshGameSpeed()

end

function LFightManager:IsNoNeedBackground(combatType)
    return self._noNeedBackground[combatType] or false
end

function LFightManager:TryChangeToActive(combatType, index)
    local curBattleUnit = self:GetCurBattleUnit()
    if not index then
        index = self:FindAnotherUnitIndex(combatType)
        print(string.format("active battle index %s", tostring(index)))
    end

    if not index then
        return
    end
    local battleUnit = self:GetBattleByType(combatType, index)
    if not battleUnit then
        return false
    end
    local isEnd = battleUnit:IsEndExecute()
    if isEnd then
        return false
    end

    if not battleUnit:IsBackgroundPlay() then
        return true
    end

    if curBattleUnit then
        if curBattleUnit == battleUnit then
            return true
        else
            curBattleUnit:ChangeToBackground()
        end
    end

    self:SetCurCombatType(combatType)

    local extraData = battleUnit:GetCombatExtraData()
    extraData.isNew = false
    extraData.index = index
    local fullExtraData = self:FormatBattleExtraData(extraData)
    local isSceneReady = self:IsBattleSceneReady(combatType, fullExtraData.battleMapName)
    battleUnit:SetProtectOnToFront()

    if isSceneReady then
        battleUnit:AttachMapTrans(self._mapTrans)
        battleUnit:ResumeBattleToFront()
        --self:ClearWaitRemoveBattleQueue()
        self:PlayMapMusic(battleUnit:GetCombatExtraData())
    else
        battleUnit:SetIsTransmit(true)
        GF.ChangeMap("LBattleMap", false, { combatType = combatType, extraData = fullExtraData })
    end

    return true
end

function LFightManager:OnBackgroundToFront(combatType, index)
    index = index or 1
    local battleUnit = self:GetBattleByType(combatType, index)
    if not battleUnit then
        return
    end
    battleUnit:AttachMapTrans(self._mapTrans)
    battleUnit:ResumeBattleToFront()
    self:PlayMapMusic(battleUnit:GetCombatExtraData())

    gModelGameHelper:RefreshGameSpeed()

end

function LFightManager:FormatBattleExtraData(combatData)
    if not combatData.battleMapName then
        local mapRes = gModelBattle:GetBattleMapRes(combatData)
        combatData.battleMapName = mapRes
    end
    if not combatData.musicName then
        local musicRes = gModelBattle:GetBattleBgMusic(combatData.combatType)
        combatData.musicName = musicRes
    end
    return combatData
end

function LFightManager:PlayMapMusic(combatExtraData)
    if gLGameAudio then
        local musicName
        if combatExtraData then
            musicName = combatExtraData.musicName
        end
        if string.isempty(musicName) then
            musicName = LxResPathUtil.GetAudioSoundNameByRefId(LSoundConst.BATTLE_MUSIC)
        end
        if not string.isempty(musicName) then
            gLGameAudio:PlayMapMusic(musicName)
        end
    end
end

function LFightManager:ExitBattle(combatType)
    self:ExitBattleImpl(combatType)
end




