function LFightManager:SkipBattle(combatType, isChangeBot, noEndFunc, extraFunc)
    self:SkipBattleImpl(combatType, isChangeBot, noEndFunc, extraFunc)
end

function LFightManager:OnClickBattleClose(combatType)
    self:SkipBattleImpl(combatType)
end

function LFightManager:CancelBattle(combatType)
    self:CancelBattleImpl(combatType)
end

---跳过，正常结束
function LFightManager:SkipBattleImpl(combatType, isChangeBot, noEndFunc, extraFunc)
    local battleList = self:GetCombatUnitList(combatType)
    if battleList then
        for k, v in pairs(battleList) do
            v:SkipBattleImpl(isChangeBot, noEndFunc, extraFunc)
        end
    end

    self:ClearCombatByIfAllEnd(combatType)

end

---取消战斗
function LFightManager:CancelBattleImpl(combatType)
    local battleList = self:GetCombatUnitList(combatType)
    if battleList then
        local resultKey = nil
        for k, v in pairs(battleList) do
            v:ExitBattleImpl()
            resultKey = v:GetResultKey()
        end

        self:OnCancelBattle(combatType, resultKey)
    end

    self:ClearCombatByIfAllEnd(combatType)
end

---直接退出
function LFightManager:ExitBattleImpl(combatType)
    local battleList = self:GetCombatUnitList(combatType)
    if battleList then
        for k, v in pairs(battleList) do
            v:ExitBattleImpl()
        end
    end

    self:ClearCombatByIfAllEnd(combatType)
end

---跳过整场
function LFightManager:SkipBattleAll(combatType, isChangeBot, noEndFunc, extraFunc)
    local battleList = self:GetCombatUnitList(combatType)
    if not battleList then
        return
    end
    for k, v in ipairs(battleList) do
        v:SkipBattleAllImpl(isChangeBot, noEndFunc, extraFunc)
    end

    self:ClearCombatByIfAllEnd(combatType)
end

---@return LFightUnit
function LFightManager:GetBattleByType(combatType, index)
    if not self._runningBattles then
        return
    end

    index = index or 1
    local list = self._runningBattles[combatType]
    if not list then
        return
    end

    return list[index]

end

