function LFightManager:IsCombatTypeInFight(combatType)
    if gModelBattle:IsEndlessCombat(combatType) then
        if gModelEndles:IsEndlessFighting() then
            local endlessCombatType = gModelEndles:GetCurFightCombatType()
            if endlessCombatType == combatType then
                return true
            end
        end
    end

    local battle = nil
    local list = self:GetCombatUnitList(combatType)
    if list then
        for k, v in pairs(list) do
            if not v:IsEndExecute() then
                battle = v
            end
        end
    end

    if not battle then
        return false
    end

    local para = nil
    if combatType == LCombatTypeConst.COMBAT_DUNGEON_DAILY then
        para = battle:GetTargetLevel()
    end

    return true, para
end

