function LFightManager:IsFightIntFront(combatType)

    local curBattleUnit = self:GetCurBattleUnit()
    if not curBattleUnit then
        return false
    end

    local curCombatType = curBattleUnit:GetCombatType()
    if combatType ~= curCombatType then
        return false
    end

    if curBattleUnit:IsEndExecute() then
        return false
    end

    --if curBattleUnit:IsBackgroundPlay() then
    --	return false
    --end

    return true
end

function LFightManager:HasBattleInFront()
    local curBattleUnit = self:GetCurBattleUnit()
    if not curBattleUnit then
        return false
    end

    if curBattleUnit:IsEndExecute() then
        return false
    end
    --
    --if curBattleUnit:IsBackgroundPlay() then
    --	return false
    --end

    return true
end

-- 取消本次战斗
function LFightManager:OnCancelBattle(combatType, reportId)
    gModelBattle:OnCombatResultReq(reportId, combatType, true)
end

function LFightManager:CheckAllEnd(combatType)
    local list = self:GetCombatUnitList(combatType)
    if list then
        for k, v in pairs(list) do
            if not v:IsEndExecute() then
                return false
            end
        end
    end

    return true
end
---@param battleUnit LFightUnit
function LFightManager:OnBattlePlayEnd(battleUnit)

    local combatType = battleUnit:GetCombatType()
    local isBackGround = battleUnit:IsBackgroundPlay()
    local isAllEnd = self:CheckAllEnd(combatType)
    if isAllEnd then
        if LOG_INFO_ENABLED then
            print("---------------is all battle end")
        end

        if self:IsVideoCombat(combatType) then
            gModelBattle:RecordVideoBattleLife(combatType, false)
        end

        if self:IsNoAccountWnd(combatType) or combatType == LCombatTypeConst.COMBAT_CROSSGRADING_RANK then
            gModelBattle:ClearTipWnd(combatType)

            local endFunc = battleUnit:GetBattleEndFun()
            battleUnit:DoExtraFun()
            if endFunc then
                endFunc()
            end
        else
            local isWin = battleUnit:IsWin()
            local resultKey = battleUnit:GetResultKey()
            self:RecordBattleBackState(resultKey, isBackGround)

            gModelBattle:ReqBattleAccountInfo(resultKey, combatType, isWin)
        end

        battleUnit:DelayRemoveFromMap()

        FireEvent(EventNames.BATTLE_BACK_END)
    else
        if not isBackGround then
            local index = self:FindAnotherUnitIndex(combatType)
            self:TryChangeToActive(combatType, index)
            FireEvent(EventNames.ON_CHANGE_BATTLE_PLAY_INDEX, index)
        else
            battleUnit:DelayRemoveFromMap()
        end
    end

    if not isBackGround then
        gModelGameHelper:RefreshGameSpeed()
    end
end

------------------------------------------------------------------
function LFightManager:GetBattleCache()
    if not self._battleCache then
        local LFightCache = LxRequire("LApp.gameplay.fight.Cache.LFightCache")
        local battleCache = LFightCache:New()
        self._battleCache = battleCache
        battleCache:Create()
        return battleCache
    end
    return self._battleCache
end

function LFightManager:CountHurt(aId, hurt)
    if not self._hurtMap then
        self._hurtMap = {}
    end
    local totalHurt = self._hurtMap[aId] or 0

    totalHurt = totalHurt + hurt
    self._hurtMap[aId] = totalHurt
end

function LFightManager:ReportStatistic(reportId)

    self._hurtMap = nil

    local filePath = CS.AppPersistentDataPath() .. "fightlog/" .. reportId .. ".log"
    local bytes = CS.FileReadBytes(filePath)
    local msgId = LProtoHelper.GetProtoId("CombatReportResp")
    local protoReader = PJXProtoMessage.New()
    protoReader:SetMessage(bytes)
    local reportTable = LProtoHelper.ConvertToProto(msgId,protoReader:GetMessage())
    local battleReportData = LFightReportData:New()
    battleReportData:InitReportData(reportTable, true)

    for k, v in pairs(self._hurtMap) do
        printInfoN(string.format("aid %s, total hurt %s", k, v))
    end

end

function LFightManager:OnApplicationPause(focus)
    if focus then
        self._backgroundTime = Time.RawUnityEngineTime.realtimeSinceStartup
    else
        if self._backgroundTime then
            local timePast = Time.RawUnityEngineTime.realtimeSinceStartup - self._backgroundTime
            if timePast < 0 then
                return
            end
            local battleUnit = self:GetCurBattleUnit()
            if not battleUnit then
                return
            end
            if battleUnit:IsBackgroundPlay() then
                return
            else
                battleUnit:ChaseTo(timePast)
            end
        end
    end
end

---记录结算状态
function LFightManager:RecordBattleBackState(resultKey, isBack)
    if not self._battleStateMap then
        self._battleStateMap = {}
    end

    self._battleStateMap[resultKey] = isBack
end

function LFightManager:ClearBattleState(resultKey)
    if not self._battleStateMap then
        return
    end
    self._battleStateMap[resultKey] = nil
end

function LFightManager:GetBattleState(resultKey)
    if self._battleStateMap then
        return self._battleStateMap[resultKey]
    end
end

function LFightManager:CheckStartBattleState(combatType)
    local wnds = self._combatRelaWndMap[combatType]
    if not wnds then
        return
    end
    local isFront = gLGameUI:IsExistOneWnd(wnds)
    return isFront
end

function LFightManager:CanBattleToFront(combatType)
    local battle = self:GetBattleByType(combatType)
    if battle and not battle:IsEndExecute() then
        return true
    end

    return false
end

function LFightManager:ClearCombatByIfAllEnd(combatType)

    if not self._runningBattles then
        return
    end

    local list = self._runningBattles[combatType]
    if not list then
        return
    end

    for k, v in pairs(list) do
        if not v:IsEndExecute() then
            return
        end
    end

    for k, v in pairs(list) do
        v:Destroy()
    end

    self._runningBattles[combatType] = nil
end

function LFightManager:AddCombatByType(combatType, combatUnit)
    if not self._runningBattles then
        self._runningBattles = {}
    end

    local index = combatUnit:GetCombatIndex() or 1

    local list = self._runningBattles[combatType]
    if not list then
        list = {}
        self._runningBattles[combatType] = list
    end

    local oldBattleUnit = list[index]
    table.insert(self._waitDestroyBattle, oldBattleUnit)

    list[index] = combatUnit

    self:DestroyOldBattle()

    FireEvent(EventNames.ON_ADD_NEW_BATTLE)
end

---@return table<number,LFightUnit>
function LFightManager:GetCombatUnitList(combatType)
    local list = self._runningBattles and self._runningBattles[combatType]
    return list or {}
end
---@return LFightUnit
function LFightManager:FindAnotherUnitIndex(combatType)
    local list = self:GetCombatUnitList(combatType)
    local index = nil
    if list then
        for k, v in pairs(list) do
            if not v:IsEndExecute() then
                if not index or index > k then
                    index = k
                end
            end
        end
    end
    return index
end

function LFightManager:DestroyOldBattle()
    if self._waitDestroyBattle then
        for k, v in pairs(self._waitDestroyBattle) do
            v:Destroy()
        end

        self._waitDestroyBattle = {}
    end
end

------------------------------------------------------------------
function LFightManager:Destroy()
    self:ClearAllBattle()
    if self._battleCache then
        self._battleCache:Destroy()
    end
    LGpBaseMgr.Destroy(self)
end

return LFightManager